namespace {
class BufferOverflowChecker : public Checker<check::PreCall> {
  mutable std::unique_ptr<BugType> BT;

  static bool isUnboundedWrite(StringRef FuncName) {
    return FuncName == "strcpy" || FuncName == "strcat" || FuncName == "gets";
  }

  static std::optional<unsigned> getSizeArgIndex(StringRef FuncName) {
    if (FuncName == "memcpy" || FuncName == "memmove" || FuncName == "strncpy")
      return 2;
    if (FuncName == "snprintf")
      return 1;
    return std::nullopt;
  }

  std::optional<uint64_t> getStaticRegionSize(const MemRegion *Region,
                                              CheckerContext &C) const {
    const auto *TypedRegion = dyn_cast<TypedValueRegion>(Region->StripCasts());
    if (!TypedRegion)
      return std::nullopt;

    QualType QT = TypedRegion->getValueType();
    if (QT.isNull() || QT->isIncompleteType())
      return std::nullopt;

    return C.getASTContext().getTypeSizeInChars(QT).getQuantity();
  }

  std::optional<uint64_t> getConcreteUnsigned(SVal Value) const {
    if (auto CI = Value.getAs<nonloc::ConcreteInt>())
      return CI->getValue().getLimitedValue();
    return std::nullopt;
  }

  void report(const Stmt *S, CheckerContext &C, StringRef Message) const {
    if (ExplodedNode *N = C.generateNonFatalErrorNode()) {
      auto R = std::make_unique<PathSensitiveBugReport>(*BT, Message, N);
      if (S)
        R->addRange(S->getSourceRange());
      C.emitReport(std::move(R));
    }
  }

public:
  BufferOverflowChecker()
      : BT(std::make_unique<BugType>(this, "Buffer overflow", "Memory Error")) {}

  void checkPreCall(const CallEvent &Call, CheckerContext &C) const {
    const IdentifierInfo *II = Call.getCalleeIdentifier();
    if (!II)
      return;

    StringRef FuncName = II->getName();
    std::optional<unsigned> SizeIndex = getSizeArgIndex(FuncName);
    if (!isUnboundedWrite(FuncName) && !SizeIndex)
      return;

    if (Call.getNumArgs() == 0)
      return;

    const MemRegion *DestRegion = Call.getArgSVal(0).getAsRegion();
    if (!DestRegion)
      return;

    std::optional<uint64_t> DestBytes = getStaticRegionSize(DestRegion, C);
    if (!DestBytes)
      return;

    if (isUnboundedWrite(FuncName)) {
      report(Call.getOriginExpr(), C,
             "Unbounded write into fixed-size destination buffer");
      return;
    }

    if (Call.getNumArgs() <= *SizeIndex)
      return;

    std::optional<uint64_t> RequestedBytes =
        getConcreteUnsigned(Call.getArgSVal(*SizeIndex));
    if (!RequestedBytes)
      return;

    if (*RequestedBytes > *DestBytes) {
      report(Call.getOriginExpr(), C,
             "Copy length exceeds destination buffer size");
    }
  }
};
} // namespace

extern "C" void clang_registerCheckers(CheckerRegistry &registry) {
  registry.addChecker<BufferOverflowChecker>("custom.BufferOverflowChecker",
                                             "Check fixed-size buffers against write length",
                                             "");
}

class BufferOverflowChecker : public Checker<check::PreCall> {
  std::optional<uint64_t> getStaticDestinationBytes(const MemRegion *Region,
                                                    ASTContext &Ctx) const {
    if (!Region)
      return std::nullopt;
    const MemRegion *Base = Region->StripCasts();
    while (const auto *Element = dyn_cast<ElementRegion>(Base))
      Base = Element->getSuperRegion();
    if (const auto *Field = dyn_cast<FieldRegion>(Base)) {
      QualType QT = Field->getDecl()->getType();
      if (!QT.isNull() && !QT->isIncompleteType() &&
          (QT->isArrayType() || Ctx.getAsConstantArrayType(QT)))
        return Ctx.getTypeSizeInChars(QT).getQuantity();
    }
    if (const auto *Typed = dyn_cast<TypedValueRegion>(Base)) {
      QualType QT = Typed->getValueType();
      if (!QT.isNull() && !QT->isIncompleteType() &&
          (QT->isArrayType() || Ctx.getAsConstantArrayType(QT)))
        return Ctx.getTypeSizeInChars(QT).getQuantity();
    }
    return std::nullopt;
  }

  bool looksLikeLengthCarrier(const Expr *E) const {
    const Expr *Core = E ? E->IgnoreParenImpCasts() : nullptr;
    if (!Core)
      return false;
    if (const auto *CallExpr = dyn_cast<clang::CallExpr>(Core)) {
      if (const FunctionDecl *FD = CallExpr->getDirectCallee()) {
        StringRef Name = FD->getName();
        if (Name == "strlen" || Name == "strnlen")
          return true;
      }
    }
    if (const auto *Ref = dyn_cast<DeclRefExpr>(Core)) {
      StringRef Lowered = Ref->getDecl()->getName();
      return Lowered.contains_insensitive("len") ||
             Lowered.contains_insensitive("size") ||
             Lowered.contains_insensitive("bytes");
    }
    if (const auto *Member = dyn_cast<MemberExpr>(Core)) {
      StringRef Lowered = Member->getMemberDecl()->getName();
      return Lowered.contains_insensitive("len") ||
             Lowered.contains_insensitive("size") ||
             Lowered.contains_insensitive("bytes");
    }
    if (const auto *BinOp = dyn_cast<BinaryOperator>(Core))
      return BinOp->getOpcode() == BO_Add || BinOp->getOpcode() == BO_Sub;
    return false;
  }

  void checkPreCall(const CallEvent &Call, CheckerContext &C) const {
    const IdentifierInfo *II = Call.getCalleeIdentifier();
    if (!II)
      return;
    StringRef FuncName = II->getName();
    if (FuncName == "strcpy" || FuncName == "strcat") {
      const MemRegion *Dest = Call.getArgSVal(0).getAsRegion();
      if (!getStaticDestinationBytes(Dest, C.getASTContext()))
        return;
      if (hasSameBlockStringBarrier(Call, C, Call.getArgExpr(0), Call.getArgExpr(1)))
        return;
      reportBug(Call.getOriginExpr(), C,
                "Unsafe string write: missing destination capacity validation");
      return;
    }
    if ((FuncName == "memcpy" || FuncName == "memmove" || FuncName == "strncpy") &&
        Call.getNumArgs() > 2) {
      const MemRegion *Dest = Call.getArgSVal(0).getAsRegion();
      std::optional<uint64_t> DestBytes =
          getStaticDestinationBytes(Dest, C.getASTContext());
      const Expr *SizeArg = Call.getArgExpr(2);
      if (!DestBytes)
        return;
      if (hasSameBlockMemcpyBarrier(Call, C, Call.getArgExpr(0), SizeArg))
        return;
      if (auto Concrete = Call.getArgSVal(2).getAs<nonloc::ConcreteInt>()) {
        if (Concrete->getValue().getLimitedValue() <= *DestBytes)
          return;
      } else if (!looksLikeLengthCarrier(SizeArg)) {
        return;
      }
      reportBug(Call.getOriginExpr(), C,
                "Copy operation: missing destination capacity validation");
    }
  }
};

