namespace {
class UseAfterFreeChecker : public Checker<check::PostCall, check::Location, check::Bind> {
  mutable std::unique_ptr<BugType> BT;

  static bool isReleaseLike(StringRef FuncName) {
    return FuncName == "free" ||
           FuncName == "kfree" ||
           FuncName == "delete" ||
           FuncName == "release" ||
           FuncName.ends_with("_free") ||
           FuncName.ends_with("_release") ||
           FuncName.contains("destroy");
  }

  static SymbolRef tracked(SVal Value) {
    if (SymbolRef Sym = Value.getAsLocSymbol(true))
      return Sym;
    return Value.getAsSymbol(true);
  }

  void reportBug(const Stmt *S, StringRef Message, CheckerContext &C) const {
    if (!S)
      return;
    if (ExplodedNode *N = C.generateErrorNode()) {
      auto R = std::make_unique<PathSensitiveBugReport>(*BT, Message, N);
      R->addRange(S->getSourceRange());
      C.emitReport(std::move(R));
    }
  }

public:
  UseAfterFreeChecker()
      : BT(std::make_unique<BugType>(this, "Use after free", "Memory Error")) {}

  void checkPostCall(const CallEvent &Call, CheckerContext &C) const {
    const IdentifierInfo *II = Call.getCalleeIdentifier();
    if (!II || Call.getNumArgs() == 0 || !isReleaseLike(II->getName()))
      return;
    if (SymbolRef Released = tracked(Call.getArgSVal(0)))
      C.addTransition(C.getState()->add<FreedSymbols>(Released));
  }

  void checkLocation(SVal Loc, bool IsLoad, const Stmt *S,
                     CheckerContext &C) const {
    if (SymbolRef Accessed = tracked(Loc)) {
      if (C.getState()->contains<FreedSymbols>(Accessed)) {
        reportBug(S, IsLoad ? "Dereference of a previously released symbol"
                            : "Write through a previously released symbol",
                  C);
      }
    }
  }

  void checkBind(SVal Loc, SVal Val, const Stmt *StoreE,
                 CheckerContext &C) const {
    (void)Loc;
    if (SymbolRef Bound = tracked(Val)) {
      if (C.getState()->contains<FreedSymbols>(Bound)) {
        reportBug(StoreE,
                  "Previously released symbol is propagated through a new binding",
                  C);
      }
    }
  }
};
} // namespace

extern "C" void clang_registerCheckers(CheckerRegistry &registry) {
  registry.addChecker<UseAfterFreeChecker>("custom.UseAfterFreeChecker",
                                           "Detect dereference or propagation of released symbols",
                                           "");
}

