namespace {
class CachedPointerRelookupChecker : public Checker<check::PreStmt<MemberExpr>> {
  mutable std::unique_ptr<BugType> BT;

  static bool looksLikeStableHandleField(const FieldDecl *PointerField,
                                         const FieldDecl *Candidate) {
    if (!PointerField || !Candidate)
      return false;
    std::string PointerName = PointerField->getName().str();
    StringRef HandleName = Candidate->getName();
    return HandleName == (PointerName + "_id") ||
           HandleName == (PointerName + "Id") ||
           HandleName == (PointerName + "_handle") ||
           HandleName == (PointerName + "Handle") ||
           HandleName == (PointerName + "_key") ||
           HandleName == (PointerName + "Key");
  }

  static bool hasStableHandlePeer(const FieldDecl *PointerField) {
    const auto *Owner = PointerField ? dyn_cast<RecordDecl>(PointerField->getDeclContext()) : nullptr;
    if (!Owner)
      return false;
    for (const FieldDecl *FD : Owner->fields()) {
      if (FD != PointerField && looksLikeStableHandleField(PointerField, FD))
        return true;
    }
    return false;
  }

public:
  CachedPointerRelookupChecker()
      : BT(std::make_unique<BugType>(this, "Stale cached pointer use", "Memory Error")) {}

  void checkPreStmt(const MemberExpr *ME, CheckerContext &C) const {
    const auto *Inner = ME ? dyn_cast<MemberExpr>(ME->getBase()->IgnoreParenImpCasts()) : nullptr;
    const auto *PointerField = Inner ? dyn_cast<FieldDecl>(Inner->getMemberDecl()) : nullptr;
    if (!PointerField || !PointerField->getType()->isPointerType() || !hasStableHandlePeer(PointerField))
      return;
    if (ExplodedNode *N = C.generateNonFatalErrorNode()) {
      auto R = std::make_unique<PathSensitiveBugReport>(
          *BT,
          "Direct use of a cached pointer field bypasses authoritative relookup from a stable handle",
          N);
      R->addRange(ME->getSourceRange());
      C.emitReport(std::move(R));
    }
  }
};
} // namespace

extern "C" void clang_registerCheckers(CheckerRegistry &registry) {
  registry.addChecker<CachedPointerRelookupChecker>(
      "custom.CachedPointerRelookupChecker",
      "Detect direct dereference of cached managed pointers that bypass authoritative relookup",
      "");
}
